import React from 'react';
import { Card, Stack, Text, Divider } from '@ggui-ai/design/primitives';

interface ForecastItem {
  day?: string;
  icon?: string;
  high?: number;
  low?: number;
}

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit?: string;
  forecast?: ForecastItem[];
}

export default function GeneratedComponent({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = '°C',
  forecast = [],
}: Props) {
  return (
    <div role="region" aria-label={`Weather in ${city}`}>
      <Card shadow="md" padding={24} radius="lg">
        <Stack gap={24}>
          {/* Current Weather */}
          <Stack align="center" gap={4}>
            <Text variant="bodyLarge" weight="semibold">
              {city}
            </Text>
            <Text size="4xl" weight="bold">
              {temperature}
              {unit}
            </Text>
            <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">
              {condition}
            </Text>
          </Stack>

          {/* Metrics */}
          <Stack direction="horizontal" justify="between">
            <Stack align="center" aria-label={`Humidity is ${humidity} percent`}>
              <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
                Humidity
              </Text>
              <Text variant="body" weight="semibold">
                {humidity}%
              </Text>
            </Stack>
            <Stack align="center" aria-label={`Wind speed is ${windSpeed} km/h`}>
              <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
                Wind
              </Text>
              <Text variant="body" weight="semibold">
                {windSpeed} km/h
              </Text>
            </Stack>
          </Stack>

          <Divider margin={0} />

          {/* Forecast */}
          <Stack direction="horizontal" justify="between">
            {forecast.map((item, i) => (
              <Stack key={i} align="center" gap={4}>
                <Text variant="caption">{item.day ?? 'N/A'}</Text>
                <Text variant="bodyLarge">{item.icon ?? '☁️'}</Text>
                <Text variant="bodySmall">
                  {item.high ?? 0}°/{item.low ?? 0}°
                </Text>
              </Stack>
            ))}
          </Stack>
        </Stack>
      </Card>
    </div>
  );
}

import React, { useState, useMemo } from 'react';
import { Container, Box, Stack, Text, Heading, Card } from '@ggui-ai/design/primitives';
import { Input } from '@ggui-ai/design/components';

interface Props {
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

export default function PeriodicTableComponent(props: Props) {
  const [selectedElement, setSelectedElement] = useState<Props['elements'][0] | null>(null);
  const [searchQuery, setSearchQuery] = useState('');

  const filteredElements = useMemo(() => {
    const query = searchQuery.toLowerCase();
    return props.elements.filter(
      (el) =>
        el.name?.toLowerCase().includes(query) ||
        el.symbol?.toLowerCase().includes(query)
    );
  }, [props.elements, searchQuery]);

  const getCategoryColor = (category?: string) => {
    switch (category) {
      case 'noble-gas': return 'var(--ggui-color-primary-200, #bae6fd)';
      case 'nonmetal': return 'var(--ggui-color-success-100, #dcfce7)';
      case 'halogen': return 'var(--ggui-color-warning-100, #fef3c7)';
      case 'alkali-metal': return 'var(--ggui-color-error-100, #fee2e2)';
      default: return 'var(--ggui-color-neutral-100, #f3f4f6)';
    }
  };

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-8, 32px)">
      <Stack gap="var(--ggui-spacing-4, 16px)">
        <Heading level={1}>Periodic Table</Heading>
        <Input 
          label="Search Elements" 
          placeholder="Search by name or symbol..." 
          value={searchQuery} 
          onChange={setSearchQuery} 
        />

        <Box style={{ 
          display: 'grid', 
          gridTemplateColumns: 'repeat(18, 1fr)', 
          gap: 'var(--ggui-spacing-1, 4px)' 
        }}>
          {filteredElements.map((el) => (
            <Box
              key={el.atomicNumber}
              onClick={() => setSelectedElement(el)}
              padding="var(--ggui-spacing-2, 8px)"
              background={getCategoryColor(el.category)}
              borderRadius="var(--ggui-shape-radius-sm, 4px)"
              style={{ 
                gridRow: el.row, 
                gridColumn: el.col, 
                cursor: 'pointer',
                aspectRatio: '1/1'
              }}
            >
              <Text variant="caption">{el.atomicNumber}</Text>
              <Heading level={6} align="center">{el.symbol}</Heading>
            </Box>
          ))}
        </Box>

        {selectedElement && (
          <Card shadow="md" padding="var(--ggui-spacing-4, 16px)">
            <Stack gap="var(--ggui-spacing-2, 8px)">
              <Heading level={3}>{selectedElement.name}</Heading>
              <Text>Symbol: {selectedElement.symbol}</Text>
              <Text>Atomic Number: {selectedElement.atomicNumber}</Text>
              <Text>Atomic Weight: {selectedElement.atomicWeight}</Text>
              <Text>Category: {selectedElement.category}</Text>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Heading,
  Box,
  Divider,
  Spacer
} from '@ggui-ai/design/primitives';

interface ForecastItem {
  day?: string;
  icon?: string;
  high?: number;
  low?: number;
}

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: ForecastItem[];
}

export default function GeneratedComponent({
  city = "Tokyo",
  temperature = 28,
  condition = "Sunny",
  humidity = 45,
  windSpeed = 8,
  unit = "C",
  forecast = [
    { day: "Mon", icon: "☀️", high: 30, low: 22 },
    { day: "Tue", icon: "⛅", high: 27, low: 20 },
    { day: "Wed", icon: "🌧️", high: 24, low: 18 },
    { day: "Thu", icon: "☁️", high: 26, low: 19 },
    { day: "Fri", icon: "☀️", high: 29, low: 21 }
  ]
}: Props) {
  const [isHovered, setIsHovered] = useState(false);

  return (
    <div
      role="region"
      aria-label={`Weather information for ${city ?? 'current city'}`}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      style={{
        maxWidth: '400px',
        width: '100%',
        transition: 'transform 200ms cubic-bezier(0, 0, 0.2, 1)',
        transform: isHovered ? 'scale(1.01)' : 'scale(1)',
      }}
    >
      <Card shadow="md" padding={24} radius="xl">
        <Stack gap={20}>
          {/* Header Section */}
          <Stack gap={4}>
            <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
              {city ?? 'Unknown City'}
            </Heading>
            <Text
              variant="body"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              {condition ?? 'Clear'}
            </Text>
          </Stack>

          {/* Hero Section */}
          <Stack align="center" gap={16}>
            <Heading
              level={1}
              color="var(--ggui-color-primary-600, #0284c7)"
              style={{ fontSize: 'var(--ggui-font-size-4xl, 36px)' }}
            >
              {temperature ?? 0}°{unit ?? 'C'}
            </Heading>

            {/* Details Row */}
            <Stack direction="horizontal" gap={12} justify="center" wrap>
              <Box
                paddingX={16}
                paddingY={8}
                background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                borderRadius="var(--ggui-shape-radius-lg, 12px)"
              >
                <Stack direction="horizontal" gap={8} align="center">
                  <Text size="sm" weight="medium">💧</Text>
                  <Stack gap={0}>
                    <Text variant="caption" weight="semibold">HUMIDITY</Text>
                    <Text variant="bodySmall">{humidity ?? 0}%</Text>
                  </Stack>
                </Stack>
              </Box>

              <Box
                paddingX={16}
                paddingY={8}
                background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                borderRadius="var(--ggui-shape-radius-lg, 12px)"
              >
                <Stack direction="horizontal" gap={8} align="center">
                  <Text size="sm" weight="medium">🌬️</Text>
                  <Stack gap={0}>
                    <Text variant="caption" weight="semibold">WIND</Text>
                    <Text variant="bodySmall">{windSpeed ?? 0} km/h</Text>
                  </Stack>
                </Stack>
              </Box>
            </Stack>
          </Stack>

          <Divider margin={8} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

          {/* Forecast Section */}
          <Stack
            direction="horizontal"
            justify="between"
            gap={4}
            aria-label="5-day forecast"
          >
            {(forecast ?? []).map((item, index) => (
              <Box
                key={`${item.day}-${index}`}
                padding={8}
                borderRadius="var(--ggui-shape-radius-md, 8px)"
                style={{
                  flex: 1,
                  textAlign: 'center',
                  transition: 'background 200ms ease',
                  cursor: 'default'
                }}
              >
                <Stack align="center" gap={4}>
                  <Text
                    variant="overline"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    {item.day ?? '---'}
                  </Text>
                  <Text
                    size="lg"
                    aria-hidden="true"
                    style={{ marginY: 'var(--ggui-spacing-1, 4px)' }}
                  >
                    {item.icon ?? '☀️'}
                  </Text>
                  <Text variant="caption" weight="medium" truncate>
                    {item.high ?? 0}° / {item.low ?? 0}°
                  </Text>
                </Stack>
              </Box>
            ))}
          </Stack>
        </Stack>
      </Card>
    </div>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Stack,
  Box,
  Card,
  Text,
  Heading,
  Divider,
  Spacer,
  Badge
} from '@ggui-ai/design/primitives';
import { SearchField } from '@ggui-ai/design/components';

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Full periodic table element data */
  elements: ElementData[];
}

export default function GeneratedComponent({
  elements = []
}: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);

  const categoryColors: Record<string, { bg: string; text: string }> = {
    'nonmetal': { bg: 'var(--ggui-color-primary-100, #e0f2fe)', text: 'var(--ggui-color-primary-800, #075985)' },
    'noble-gas': { bg: 'var(--ggui-color-success-100, #dcfce7)', text: 'var(--ggui-color-success-800, #166534)' },
    'alkali-metal': { bg: 'var(--ggui-color-error-100, #fee2e2)', text: 'var(--ggui-color-error-800, #991b1b)' },
    'alkaline-earth-metal': { bg: 'var(--ggui-color-warning-100, #fef3c7)', text: 'var(--ggui-color-warning-800, #92400e)' },
    'metalloid': { bg: 'var(--ggui-color-info-100, #cffafe)', text: 'var(--ggui-color-info-800, #155e75)' },
    'halogen': { bg: 'var(--ggui-color-primary-200, #bae6fd)', text: 'var(--ggui-color-primary-900, #0c4a6e)' },
    'transition-metal': { bg: 'var(--ggui-color-neutral-100, #f3f4f6)', text: 'var(--ggui-color-neutral-700, #374151)' },
    'post-transition-metal': { bg: 'var(--ggui-color-neutral-200, #e5e7eb)', text: 'var(--ggui-color-neutral-800, #1f2937)' },
    'lanthanide': { bg: 'var(--ggui-color-primary-50, #f0f9ff)', text: 'var(--ggui-color-primary-600, #0284c7)' },
    'actinide': { bg: 'var(--ggui-color-error-50, #fef2f2)', text: 'var(--ggui-color-error-600, #dc2626)' }
  };

  const filteredElements = useMemo(() => {
    const query = searchQuery.toLowerCase().trim();
    if (!query) return elements;
    return elements.filter(
      (el) =>
        el.name?.toLowerCase().includes(query) ||
        el.symbol?.toLowerCase().includes(query)
    );
  }, [elements, searchQuery]);

  const selectedElement = useMemo(
    () => elements.find((el) => el.atomicNumber === selectedAtomicNumber),
    [elements, selectedAtomicNumber]
  );

  const getStyleForCategory = (category?: string) => {
    return categoryColors[category ?? ''] || { bg: 'var(--ggui-color-surfaceVariant)', text: 'var(--ggui-color-onSurface)' };
  };

  return (
    <Container maxWidth="3xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-8, 32px)">
        {/* Header & Search */}
        <Stack gap="var(--ggui-spacing-4, 16px)">
          <Heading level={1}>Periodic Table</Heading>
          <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-4, 16px)" wrap>
            <Box style={{ flex: '1', minWidth: 'var(--ggui-spacing-12, 300px)' }}>
              <SearchField
                value={searchQuery}
                onChange={setSearchQuery}
                placeholder="Search elements by name or symbol..."
                size="md"
              />
            </Box>
            <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" wrap>
              {Object.keys(categoryColors).map((cat) => (
                <Stack key={cat} direction="horizontal" align="center" gap="var(--ggui-spacing-1, 4px)">
                  <Box
                    style={{
                      width: 'var(--ggui-spacing-4, 16px)',
                      height: 'var(--ggui-spacing-4, 16px)',
                      borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                      backgroundColor: categoryColors[cat].bg,
                      border: '1px solid var(--ggui-color-outline, #d4d4d8)'
                    }}
                  />
                  <Text variant="caption" style={{ textTransform: 'capitalize' }}>
                    {cat.replace(/-/g, ' ')}
                  </Text>
                </Stack>
              ))}
            </Stack>
          </Stack>
        </Stack>

        {/* Periodic Table Grid */}
        <Box style={{ overflowX: 'auto', paddingBottom: 'var(--ggui-spacing-4, 16px)' }}>
          <div
            role="grid"
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, minmax(var(--ggui-spacing-12, 48px), 1fr))',
              gap: 'var(--ggui-spacing-1, 4px)',
              minWidth: 'var(--ggui-spacing-12, 900px)'
            }}
          >
            {(elements ?? []).map((el) => {
              const isMatch = filteredElements.some((fe) => fe.atomicNumber === el.atomicNumber);
              const isSelected = selectedAtomicNumber === el.atomicNumber;
              const colors = getStyleForCategory(el.category);

              return (
                <div
                  key={el.atomicNumber}
                  role="gridcell"
                  tabIndex={0}
                  aria-label={`${el.name ?? 'Element'} (${el.symbol ?? '?'}), Atomic Number ${el.atomicNumber ?? '?'}`}
                  onClick={() => setSelectedAtomicNumber(el.atomicNumber ?? null)}
                  onKeyDown={(e) => {
                    if (e.key === 'Enter' || e.key === ' ') {
                      e.preventDefault();
                      setSelectedAtomicNumber(el.atomicNumber ?? null);
                    }
                  }}
                  style={{
                    gridRow: el.row,
                    gridColumn: el.col,
                    cursor: 'pointer',
                    transition: 'transform 200ms ease-in-out, opacity 200ms ease-in-out',
                    transform: isSelected ? 'scale(1.1)' : 'scale(1)',
                    zIndex: isSelected ? 10 : 1,
                    opacity: isMatch ? 1 : 0.1,
                    pointerEvents: isMatch ? 'auto' : 'none'
                  }}
                >
                  <Card
                    padding="var(--ggui-spacing-1, 4px)"
                    shadow={isSelected ? 'md' : 'none'}
                    radius="md"
                    border={!isSelected}
                    style={{
                      height: '100%',
                      aspectRatio: '1/1',
                      display: 'flex',
                      flexDirection: 'column',
                      justifyContent: 'center',
                      alignItems: 'center',
                      backgroundColor: colors.bg,
                      borderColor: isSelected ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-outlineVariant, #e4e4e7)',
                      position: 'relative'
                    }}
                  >
                    <Text
                      variant="caption"
                      weight="medium"
                      style={{
                        position: 'absolute',
                        top: 'var(--ggui-spacing-1, 4px)',
                        left: 'var(--ggui-spacing-1, 4px)',
                        fontSize: 'var(--ggui-font-size-xs, 10px)',
                        color: colors.text
                      }}
                    >
                      {el.atomicNumber}
                    </Text>
                    <Text
                      variant="body"
                      weight="bold"
                      style={{ color: colors.text, fontSize: 'var(--ggui-font-size-base, 16px)' }}
                    >
                      {el.symbol}
                    </Text>
                    <Text
                      variant="caption"
                      truncate
                      style={{
                        fontSize: 'var(--ggui-font-size-xs, 9px)',
                        color: colors.text,
                        width: '100%',
                        textAlign: 'center'
                      }}
                    >
                      {el.name}
                    </Text>
                  </Card>
                </div>
              );
            })}
          </div>
        </Box>

        {/* Detail Panel */}
        {selectedElement ? (
          <div style={{ animation: 'ggui-slideInUp 300ms ease-out' }}>
            <Card shadow="md" padding="var(--ggui-spacing-6, 24px)" radius="xl" style={{ backgroundColor: 'var(--ggui-color-surface, #fafafa)' }}>
              <Stack direction="horizontal" align="center" justify="between" wrap>
                <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-4, 16px)">
                  <Box
                    padding="var(--ggui-spacing-4, 16px)"
                    borderRadius="var(--ggui-shape-radius-lg, 12px)"
                    background={getStyleForCategory(selectedElement.category).bg}
                    style={{ minWidth: 'var(--ggui-spacing-12, 80px)', textAlign: 'center' }}
                  >
                    <Heading level={1} color={getStyleForCategory(selectedElement.category).text}>
                      {selectedElement.symbol}
                    </Heading>
                  </Box>
                  <Stack gap="var(--ggui-spacing-1, 4px)">
                    <Heading level={2}>{selectedElement.name}</Heading>
                    <Badge variant="primary" size="lg">
                      {selectedElement.category?.replace(/-/g, ' ')}
                    </Badge>
                  </Stack>
                </Stack>
                <Box style={{ textAlign: 'right' }}>
                  <Text variant="overline" color="var(--ggui-color-neutral-500, #6b7280)">Atomic Number</Text>
                  <Heading level={3}>{selectedElement.atomicNumber}</Heading>
                </Box>
              </Stack>

              <Divider margin="var(--ggui-spacing-6, 24px)" />

              <Stack direction="horizontal" gap="var(--ggui-spacing-8, 32px)" wrap>
                <Stack gap="var(--ggui-spacing-1, 4px)">
                  <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">Atomic Weight</Text>
                  <Text variant="bodyLarge" weight="semibold">{selectedElement.atomicWeight} u</Text>
                </Stack>
                <Stack gap="var(--ggui-spacing-1, 4px)">
                  <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">Category</Text>
                  <Text variant="bodyLarge" weight="semibold" style={{ textTransform: 'capitalize' }}>
                    {selectedElement.category?.replace(/-/g, ' ')}
                  </Text>
                </Stack>
                <Spacer size="flex" />
              </Stack>
            </Card>
          </div>
        ) : (
          <Box padding="var(--ggui-spacing-8, 32px)" style={{ textAlign: 'center', backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)', borderRadius: 'var(--ggui-shape-radius-lg, 12px)' }}>
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Select an element from the table to view detailed properties.
            </Text>
          </Box>
        )}
      </Stack>
    </Container>
  );
}
